+
+  IdType* q_indptr;
+  IdType* kv_indptr;
+  IdType* partial_indptr;
+  IdType* kv_indices;
+  IdType* q_len;
+  IdType* kv_len;
+  IdType* q_start;
+  IdType* kv_start;
+  IdType* kv_end;
+  IdType* kv_head_idx_arr;
+  IdType* work_indptr;
+  IdType* len_kv_chunk;
+
+  // for state reduction
+  IdType* merge_indptr;
+  IdType* merge_o_indices;
+  IdType* num_packed_qo_len;
+
+  uint32_t num_kv_heads;
+  uint_fastdiv gqa_group_size;
+  uint_fastdiv page_size;
+
+  uint32_t q_stride_n;
+  uint32_t q_stride_h;
+  uint32_t k_stride_page;
+  uint32_t k_stride_h;
+  uint32_t k_stride_n;
+  uint32_t v_stride_page;
+  uint32_t v_stride_h;
+  uint32_t v_stride_n;
+
+  float sm_scale;
+
+  {{ additional_params_decl }}
+
+  PROFILER_PARAMS_DECL
+};

